const potentialSlots = [];

const config = $('1. CONFIGURATION').item.json;

// FIX 1: saugus paėmimas + aiški klaida vietoj split crash
const initialISO =
  $('Webhook: Production URL = VAPI Server URL').item?.json?.body?.message?.toolCalls?.[0]?.function?.arguments?.initialSearchDateTime;

if (!initialISO || typeof initialISO !== 'string') {
  return [{
    json: {
      error: 'initialSearchDateTime nerastas webhook payload’e (toolCalls[0].function.arguments.initialSearchDateTime)',
      gotToolCalls: $('Webhook: Production URL = VAPI Server URL').item?.json?.body?.message?.toolCalls ?? null,
    }
  }];
}

const datePart = initialISO.split('T')[0];

// FIX 2: offset ištraukiam teisingai (Z arba +02:00)
const tzMatch = initialISO.match(/([+-]\d{2}:\d{2}|Z)$/);
const offsetPart = tzMatch ? tzMatch[1] : '+02:00';

// FIX 3: ISO formatas su offset (kad negautum UTC Z poslinkių)
function toISOWithOffset(d, offset) {
  if (offset === 'Z') return d.toISOString().replace('.000', '');
  const m = offset.match(/^([+-])(\d{2}):(\d{2})$/);
  if (!m) return d.toISOString();

  const sign = m[1] === '-' ? -1 : 1;
  const offMin = sign * (Number(m[2]) * 60 + Number(m[3]));
  const local = new Date(d.getTime() + offMin * 60000);

  const yyyy = local.getUTCFullYear();
  const MM   = String(local.getUTCMonth() + 1).padStart(2, '0');
  const dd   = String(local.getUTCDate()).padStart(2, '0');
  const hh   = String(local.getUTCHours()).padStart(2, '0');
  const mm   = String(local.getUTCMinutes()).padStart(2, '0');
  const ss   = String(local.getUTCSeconds()).padStart(2, '0');

  return `${yyyy}-${MM}-${dd}T${hh}:${mm}:${ss}${offset}`;
}

const startHourString = String(config.workdayStartHour).padStart(2, '0');
const endHourString = String(config.workdayEndHour).padStart(2, '0');

const workdayStartISO = `${datePart}T${startHourString}:00:00${offsetPart}`;
const workdayEndISO   = `${datePart}T${endHourString}:00:00${offsetPart}`;

const workdayStart = new Date(workdayStartISO);
const workdayEnd = new Date(workdayEndISO);

const requestedStart = new Date(initialISO);

const cadenceMs = (config.bookingCadenceMinutes ?? 30) * 60000;
const minNoticeMs = (config.minNoticeMinutes ?? 30) * 60000;

const now = new Date();
const nowPlusNotice = new Date(now.getTime() + minNoticeMs);

// Startas = max( darbo pradžia, kliento prašomas, dabar+notice )
let startBase = new Date(Math.max(workdayStart.getTime(), requestedStart.getTime(), nowPlusNotice.getTime()));

// Suapvalinam į viršų iki žingsnio (cadence)
startBase = new Date(Math.ceil(startBase.getTime() / cadenceMs) * cadenceMs);

let currentSlot = startBase;

while (currentSlot.getTime() < workdayEnd.getTime()) {
  const slotEnd = new Date(currentSlot.getTime() + cadenceMs);

  // FIX 4: neleisti slotui išeiti už darbo laiko
  if (slotEnd.getTime() > workdayEnd.getTime()) break;

  potentialSlots.push({
    start: toISOWithOffset(currentSlot, offsetPart),
    end: toISOWithOffset(slotEnd, offsetPart),
  });

  currentSlot = slotEnd;
}

return [{
  json: {
    ...config,
    potentialSlots
  }
}];

